parameters.jsCode:
const raw = typeof query === 'string' ? query : query?.expression;
const expression = String(raw ?? '').trim();
if (!expression || expression.length > 200) throw new Error('Bieu thuc phai co tu 1 den 200 ky tu.');
if (!/^[0-9eE+\-*/%().\s]+$/.test(expression)) throw new Error('Chi cho phep so, dau ngoac va cac toan tu + - * / %.');
const tokens = expression.match(/(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][+\-]?\d+)?|[()+\-*/%]/g) ?? [];
if (tokens.join('') !== expression.replace(/\s+/g, '')) throw new Error('Bieu thuc so hoc khong hop le.');
let position = 0;
const peek = () => tokens[position];
const take = () => tokens[position++];
function parsePrimary() {
  const token = take();
  if (token === '(') { const value = parseExpression(); if (take() !== ')') throw new Error('Thieu dau ngoac dong.'); return value; }
  const value = Number(token);
  if (!Number.isFinite(value)) throw new Error('So khong hop le.');
  return value;
}
function parseUnary() {
  if (peek() === '+') { take(); return parseUnary(); }
  if (peek() === '-') { take(); return -parseUnary(); }
  return parsePrimary();
}
function parseTerm() {
  let value = parseUnary();
  while (['*', '/', '%'].includes(peek())) {
    const operator = take(); const right = parseUnary();
    if ((operator === '/' || operator === '%') && right === 0) throw new Error('Khong the chia cho 0.');
    if (operator === '*') value *= right;
    if (operator === '/') value /= right;
    if (operator === '%') value %= right;
  }
  return value;
}
function parseExpression() {
  let value = parseTerm();
  while (['+', '-'].includes(peek())) {
    const operator = take(); const right = parseTerm();
    value = operator === '+' ? value + right : value - right;
  }
  return value;
}
const result = parseExpression();
if (position !== tokens.length || !Number.isFinite(result)) throw new Error('Bieu thuc so hoc khong hop le.');
return JSON.stringify({ expression, result });

const agent = $input.first().json;
const answer = String(agent.output ?? '');
function parseValue(value) {
  if (typeof value !== 'string') return value;
  try { return JSON.parse(value); } catch { return value; }
}
function collectSources(value, target) {
  const parsed = parseValue(value);
  if (Array.isArray(parsed)) { for (const entry of parsed) collectSources(entry, target); return; }
  if (!parsed || typeof parsed !== 'object') return;
  const candidate = parsed.json && typeof parsed.json === 'object' ? parsed.json : parsed;
  if (candidate.chunk_id || candidate.document_code) { target.push(candidate); return; }
  for (const nested of Object.values(parsed)) collectSources(nested, target);
}
const sources = [];
for (const step of agent.intermediateSteps ?? []) {
  const toolName = String(step?.action?.tool ?? step?.tool ?? '').toLowerCase();
  if (toolName === 'rag_search' || toolName.includes('rag_search') || toolName === 'literature_lookup' || toolName.includes('literature_lookup')) {
    collectSources(step?.observation ?? step?.output ?? step?.result, sources);
  }
}
const uniqueByKey = new Map();
for (const source of sources) {
  const key = String(source.chunk_id ?? [source.document_code, source.page_number, source.section_code].join(':'));
  if (!uniqueByKey.has(key)) uniqueByKey.set(key, source);
}
const uniqueSources = [...uniqueByKey.values()];
const webhook = $('Webhook').first().json;
const request = webhook.body ?? webhook;
const memory = $('Load Memory').first().json.memory ?? [];
const historyText = JSON.stringify(memory);
const tokensUsed = Math.ceil((String(request.query ?? '').length + historyText.length + answer.length) / 4);
return [{ json: { answer, sources: uniqueSources, session_id: String(request.session_id ?? ''), tokens_used: tokensUsed, sources_count: uniqueSources.length } }];

